// Format Tavily search results into a structured article digest
const results = $input.first().json.results || [];

const formatted = results.map((article, idx) => {
  const title = article.title || 'Untitled';
  const url = article.url || '';
  const content = article.content || '';
  const score = article.score || 0;
  const publishedDate = article.published_date || 'Recent';

  return `---\nArticle ${idx + 1}: ${title}\nPublished: ${publishedDate}\nRelevance Score: ${score}\nURL: ${url}\nSummary: ${content}`;
}).join('\n\n');

return [{
  json: {
    articlesFormatted: formatted,
    articleCount: results.length,
    query: $input.first().json.query || 'AI and Innovation'
  }
}];

// Error logging — write error details to execution data
return [{
  json: {
    error: true,
    errorMessage: $input.first().json.error.message || 'Unknown error',
    timestamp: new Date().toISOString(),
    workflow: 'AI & Innovation News Bot'
  }
}];
